const $ = (id) => document.getElementById(id);
let currentIndex = 0;
let isAuto = false;
let autoTimer = null;
const slides = Array.from({length:18}, (_,i)=>`assets/slides/slide-${i+1}.png`);

function fmt(sec){ sec=Number(sec)||0; const m=Math.floor(sec/60); const s=sec%60; return `${m}:${String(s).padStart(2,'0')}`; }
function sceneText(r){ return `${r.Module || ''}\n${r.Section || ''}\n${r.Scene || ''}\n\n${r.Narration || ''}`.trim(); }
function setScene(i){
  currentIndex = Math.max(0, Math.min(i, STORYBOARD.length-1));
  const r = STORYBOARD[currentIndex];
  $('sceneCount').textContent = `${currentIndex+1} / ${STORYBOARD.length}`;
  $('slideImage').src = r.slideImage || slides[currentIndex % slides.length];
  $('sceneTitle').textContent = r.Scene || 'Scene';
  $('sceneModule').textContent = r.Module || '';
  $('sceneSection').textContent = r.Section || '';
  $('sceneDuration').textContent = `${r.Duration || 0} sec`;
  $('sceneNarration').textContent = r.Narration || '';
  $('sceneVisual').textContent = r.Visual || '';
  $('sceneAvatar').textContent = r.Avatar || '';
  $('sceneNotes').textContent = r['Production Notes'] || '';
}
function nextScene(){ setScene(currentIndex+1); }
function prevScene(){ setScene(currentIndex-1); }
function speakCurrent(){
  if (!('speechSynthesis' in window)) { alert('Browser text-to-speech is not available. Use the MP3 audio player instead.'); return; }
  window.speechSynthesis.cancel();
  const utter = new SpeechSynthesisUtterance(sceneText(STORYBOARD[currentIndex]));
  utter.rate = 0.88; utter.pitch = 1.0;
  window.speechSynthesis.speak(utter);
}
function stopSpeak(){ if ('speechSynthesis' in window) window.speechSynthesis.cancel(); }
function autoPlay(){
  if (isAuto) { clearTimeout(autoTimer); isAuto=false; $('autoBtn').textContent='Auto-play scenes'; return; }
  isAuto=true; $('autoBtn').textContent='Stop auto-play';
  const run=()=>{
    if(!isAuto) return;
    setScene(currentIndex);
    speakCurrent();
    const dur = Math.max(8, Number(STORYBOARD[currentIndex].Duration || 60) / 6) * 1000;
    autoTimer=setTimeout(()=>{ if(currentIndex < STORYBOARD.length-1) { currentIndex++; run(); } else { autoPlay(); } }, dur);
  };
  run();
}
function renderTable(rows){
  const tbody=$('storyBody'); tbody.innerHTML='';
  rows.slice(0,120).forEach((r, idx)=>{
    const actual = STORYBOARD.indexOf(r);
    const tr=document.createElement('tr');
    tr.innerHTML=`<td>${r.Seq}</td><td>${r.Module}</td><td>${r.Section}</td><td>${r.Scene}</td><td>${r.Duration}s</td><td>${r.Narration}</td>`;
    tr.addEventListener('click',()=>{ setScene(actual); window.scrollTo({top:0, behavior:'smooth'}); });
    tbody.appendChild(tr);
  });
  $('tableNote').textContent = rows.length > 120 ? `Showing first 120 of ${rows.length} matched scenes. Use search to narrow the list.` : `${rows.length} scenes shown.`;
}
function filterTable(){
  const q=$('searchBox').value.toLowerCase();
  const rows = STORYBOARD.filter(r => Object.values(r).join(' ').toLowerCase().includes(q));
  renderTable(rows);
}
function renderModules(){
  const modules=[...new Set(STORYBOARD.map(r=>r.Module))];
  const grid=$('moduleGrid'); grid.innerHTML='';
  modules.forEach(m=>{
    const rows=STORYBOARD.filter(r=>r.Module===m);
    const secs=[...new Set(rows.map(r=>r.Section))].length;
    const dur=rows.reduce((a,r)=>a+(Number(r.Duration)||0),0);
    const card=document.createElement('button');
    card.className='module-card';
    card.innerHTML=`<b>${m}</b><span>${secs} sections • ${rows.length} scenes • ${Math.round(dur/60)} min</span>`;
    card.onclick=()=>{ setScene(STORYBOARD.indexOf(rows[0])); };
    grid.appendChild(card);
  });
}
window.addEventListener('DOMContentLoaded',()=>{
  $('prevBtn').onclick=prevScene; $('nextBtn').onclick=nextScene; $('speakBtn').onclick=speakCurrent; $('stopBtn').onclick=stopSpeak; $('autoBtn').onclick=autoPlay;
  $('searchBox').addEventListener('input',filterTable);
  renderModules(); setScene(0); renderTable(STORYBOARD);
});
